sql:
SELECT AVG(j.average_salary) AS average_salary
FROM job_distribution j
WHERE j.jobs_professional = (
    SELECT MAX(jobs_professional) 
    FROM job_distribution
);

SELECT COUNT(DISTINCT user_id) AS num_users_traveled_every_neighborhood
FROM (
  SELECT user_id, COUNT(DISTINCT neighborhood_id) AS num_neighborhoods
  FROM access_logs
  GROUP BY user_id
) AS user_neighborhoods
WHERE num_neighborhoods = (
  SELECT COUNT(DISTINCT neighborhood_id)
  FROM neighborhoods
);

SELECT AVG(median_income) AS AverageIncome
FROM neighborhoods
WHERE unemployment_rate = (
    SELECT MAX(unemployment_rate)
    FROM neighborhoods
);

SELECT n.name AS neighborhood_name, n.population_2020
FROM neighborhoods n
JOIN employment_stats e ON n.neighborhood_id = e.neighborhood_id
WHERE e.year = 2023 AND e.employment_growth_rate > (
    SELECT AVG(employment_growth_rate) FROM employment_stats WHERE year = 2023
);

external_knowledge:
- Average median income is used as a benchmark to identify relatively affluent neighborhoods; 
- Employment growth rate is a key indicator of the economic vitality and recovery of neighborhoods; 
- A 60% unemployment rate threshold is used to consider neighborhoods with relatively low unemployment; 
- The years 2010 and 2020 are likely chosen to reflect employment trends before and after significant economic events.
